var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루!!","JPN":"ルル！！","ENG":"Lulu!!","TWN":"露露！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜 이렇게 된 거죠? 루루가…… 정신을 못 차려요!","JPN":"これはどういうことですか？　ルルが……気絶してますよ！","ENG":"What happened to her? Lulu... She’s not waking up!","TWN":"怎麼會這樣？露露她……完全不醒人事！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루! 루루!!","JPN":"ルル！　ルル！！","ENG":"Lulu! Lulu!!","TWN":"露露！露露！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어쩌다 애가 이렇게 된 거냐구요!!","JPN":"なんでこうなったんですか！！","ENG":"How did she end up like this?!","TWN":"她怎麼會變成這樣！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"지금 이게…… 어떻게 된 상황이죠?","JPN":"今のこの状況は……どうなっているのかしら？","ENG":"What... happened here?","TWN":"這……怎麼會這樣？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……네? 헤론 님이 하신 게 아니에요?","JPN":"……え？　ヘロン様がされたんじゃないんですか？","ENG":"What...? This wasn’t your doing, Madam Heron?","TWN":"……什麼？不是夫人您做的嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당연하지! 아니, 이 여린 소녀가 뭘 할 수 있다고 이 지경으로 만들어 놨죠?","JPN":"もちろんよ！　何もできない、か弱い少女をこんな風にするなんて。","ENG":"Of course not! Who would torture a little girl like that?!","TWN":"當然不是！這麼小的孩子能做出什麼事，有必要把她打成這樣嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"누가 이런 건가요, 대체!","JPN":"誰ですか、いったい！","ENG":"Who did this?!","TWN":"到底是誰做的！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Uh...","TWN":"那個……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당신인가요?","JPN":"あなたですか？","ENG":"Was it you?","TWN":"是你嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"제가 하긴 했는데, 아까 분명 마담 명령으로……","JPN":"俺ですけど、さっき確かマダムの命令で……","ENG":"Yes, it was... But you ordered me t─","TWN":"是我做的沒錯，但剛才是夫人吩咐……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"끄… 끄아악!","JPN":"く……くはあっ！","ENG":"A-aack!","TWN":"呃…呃呃！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"히익!","JPN":"ひいっ！","ENG":"Heek!","TWN":"唔！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"마저 처리하고 오겠습니다.","JPN":"処理してきます。","ENG":"I’ll take care of it, ma’am.","TWN":"我先去把他處理乾淨。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요.","JPN":"お願いしますよ。","ENG":"Very well.","TWN":"去吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 마음이 아프네. 내 마음도 이런데, 글린다 넌 얼마나 마음이 찢어질까?","JPN":"ふう。悲しいわね。私でもこうなのに、グリンダの悲しみはどれほどか。","ENG":"Whew... It pains me to see her like this. You must be heartbroken, Glinda.","TWN":"哀，真令人心疼，我都已經這麼難過，格琳達你應該更心碎吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저런. 글린다…….","JPN":"まあ。グリンダ……","ENG":"Oh, Glinda...","TWN":"格琳達……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이미 벌어진 일은 되돌릴 수 없단다.","JPN":"すでに起こったことは取り返せないわ。","ENG":"We cannot undo what’s already been done.","TWN":"事已至此，你也別太難過。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님이 여기에 계셨다면 더했을 거야. 아마도 이 아이의 사지가 이렇게 온전히 붙어 있지도 않았겠지.","JPN":"ヘイブン様がここにいらしたらもっと酷かったと思うの。おそらくこの子の手足がこんな風に無事にくっついてなかったでしょうね。","ENG":"If Mr. Haven was here, he would’ve done worse. In the worst-case scenario, she would have lost at least one arm or leg.","TWN":"要是天堂先生在這裡，可能會更嚴重，那孩子大概無法像現在這樣四肢健全。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"알잖니. 헤이븐 님이 말 안 듣는 아이들을 어떻게 다루시는지.","JPN":"知ってるでしょう？　ヘイブン様が言うことを聞かない子たちをどう扱っているか。","ENG":"You know how Mr. Haven treats children who disobey him.","TWN":"你也很清楚吧，他都怎麼對待那些不聽話的孩子的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"너도 꽤나 말 안 듣는 축이었던 걸로 기억하는데…… 벌받던 거 기억나니?","JPN":"あなたも確かその部類だったと思うけれど……お仕置き受けたの覚えてるかしら？","ENG":"I remember you being on the disobedient side... Don’t you remember all those punishments?","TWN":"我記得你也曾經不太聽話的……你記得你被懲罰過嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"버… 벌은 안 돼요…… 벌 안 주시기로 했잖아요…….","JPN":"お……お仕置きはいけません……しないと言ったじゃないですか……","ENG":"Y-you said no punishments... You promised...","TWN":"懲罰…我不要懲罰……您不是說不會懲罰我嗎……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"걱정 마. 내가 잠시 동안은 지켜줄 테니까.","JPN":"心配しないで。しばらくは私が守ってあげるから。","ENG":"Don’t worry. I’ll protect you for the time being.","TWN":"你放心，我暫時還能保住你的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……으응. 글린다…….","JPN":"……ん。グリンダ……","ENG":"Mm... Glinda...","TWN":"……嗯，格琳達……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"정신이 들었나 보구나?","JPN":"気がついたみたいね。","ENG":"Looks like she’s finally waking up.","TWN":"你醒了嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"글린다. 내가 잠시 너희를 지켜줄 동안 이 아이가 말을 듣게끔 설득해 줄 수 있지?","JPN":"グリンダ。私がしばらくあなたたちを守ってあげる間、この子が言うことを聞くように説得してくれるわよね？","ENG":"Glinda. While I’m protecting you, could you persuade her for me please?","TWN":"格琳達，趁我還能保你們的時候，你可以說服她聽話吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이 이상 시간이 끌리면 나도 곤란해. 헤이븐 님이 워낙 성격이 급하셔서 말이야.","JPN":"これ以上長引くと私も困るのよ。ヘイブン様はとてもせっかちでいらっしゃるから。","ENG":"The more time we waste, the more Mr. Haven’s patience grows thin...","TWN":"再拖下去的話，我恐怕也無能為力，你也知道天堂先生個性很急的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이 아이들만 남기고 다들 물러가요. 둘만의 시간이 필요한 것 같으니.","JPN":"この子たちだけ残して、みんな出ていってください。二人だけの時間が必要みたいですから。","ENG":"Everyone out except these two kids. Let’s give them some time to talk in private.","TWN":"你們全都退下，留她們二人就好，她們需要一些時間獨處。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"예, 마담.","JPN":"はい、マダム。","ENG":"Yes, Madam.","TWN":"是，夫人。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"잘 부탁할게?","JPN":"よろしくね？","ENG":"I’m counting on you.","TWN":"那就麻煩你囉？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"감시는 철저히 하고 있죠? 아이들이 눈치 채지 않게 잘 해요.","JPN":"ちゃんと監視してるでしょうね？　子どもたちに気付かれないようにしっかりやりなさい。","ENG":"Are you keeping a close eye on them? Make certain that those kids don't notice.","TWN":"有派人把人看好吧？小心別被她們發現。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"예, 알겠습니다.","JPN":"はい、かしこまりました。","ENG":"Understood.","TWN":"是，夫人！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"<color=#ffd34c>정신 교란 재머</color>는 잘 작동 중인지 확인해봤나요?","JPN":"<color=#ffd34c>精神攪乱ジャマー</color>はちゃんと作動しているか確認してみましたか？","ENG":"Is the <color=#ffd34c>Mind Jammer</color> working properly?","TWN":"<color=#ffd34c>精神干擾器</color>確定有正常運作吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"예. 반항하면서 무의식 중에 능력을 사용하려는 듯했으나, 장치에 의해 발현이 제대로 안 된 것까지 확인했습니다.","JPN":"はい。抵抗しながら無意識に能力を使おうとしたようですが、装置によって発現できなかったことも確認しました。","ENG":"I confirmed it working when it prevented her from using her ability unconsciously.","TWN":"是，雖然她在反抗時下意識會想要使用能力，但因為干擾器的關係無法發揮。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"혹시 모를 상황에 대비하여 계속 확인하겠습니다.","JPN":"万が一の状況に備え、続けて確認いたします。","ENG":"I'll keep an eye on things in case something unexpected happens.","TWN":"以防萬一，我們會持續確認。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"역시. 마음에 든다니까. 마저 잘 부탁할게요.","JPN":"やっぱり。気に入りました。この後もよろしくお願いしますね。","ENG":"Perfect. I knew I could count on you. Keep up the good work.","TWN":"不錯，做得很好，那就萬事拜託囉。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루…… 정신이 들어?","JPN":"ルル……気がついた？","ENG":"Lulu... How are you holding up?","TWN":"露露……你醒了嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응.","JPN":"うん。","ENG":"Mm.","TWN":"嗯嗯。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"괜찮아? 괜찮을 리가 없지만, 그 말밖에 안 떠올라…….","JPN":"大丈夫？　大丈夫じゃないってわかってるけど、その言葉しか浮かばない……","ENG":"Are you all right? I know you're not, but that's all I can come up with...","TWN":"你還好嗎？怎麼可能還好，但我不知道還能說什麼……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"난 괜찮아, 글린다.","JPN":"私は大丈夫だよ、グリンダ。","ENG":"I’m okay, Glinda.","TWN":"格琳達，我還好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러게……! 왜 말을 안 들어서 이 지경으로 만들어!","JPN":"だから……！　なんで私の言うことを聞かないでこんなことになっちゃうんだよ！","ENG":"See...?! You should’ve just listened and it wouldn’t have gone this far!","TWN":"好……！誰叫你不聽話，把自己搞成這副德性！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"괜히 다쳤잖아, 이게 다 뭐야. 멀쩡한 곳이 없어…….","JPN":"無駄に怪我したじゃん、なに、これ。傷がないところがない……","ENG":"Look at you... You’re all bruised up...","TWN":"你看你傷成這樣！這是怎樣，根本是體無完膚……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"난 괜찮대도.","JPN":"私は大丈夫。","ENG":"I’m okay.","TWN":"我說我沒事，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"걱정해 줘서 고마워. 글린다는 역시 다정해. 착해.","JPN":"心配してくれてありがとう。やっぱりグリンダは優しい。いい子。","ENG":"I appreciate your concern though, Glinda. You’re so kind. Gentle.","TWN":"你還是那麼擔心我，謝謝你，格琳達，你真的很善良，很有愛心。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런 도움도 안 되는 소리 하지 말고!","JPN":"そんな助けにもならないこと言わないでよ！","ENG":"Don’t be absurd!","TWN":"你說那種話也沒用！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제 어쩔 거야. 이대로 있다간 매일 밤 노름꾼들의 악몽 없애 주는 기계로 전락해 버리고 말 거라고!","JPN":"もうどうするんだよ。このままじゃあ、毎晩遊び人たちの悪夢を消す機械に転落しちゃう！","ENG":"What are you gonna do now? At this rate, they'll turn you into a machine who goes around removing gamblers' nightmares!","TWN":"現在怎麼辦？繼續待在這裡的話，你就會淪落成每天替賭鬼消除惡夢的機器！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"악몽을 가져갈 수만 있다면…… 그것도 나쁘지 않겠네.","JPN":"悪夢を取り込むことさえできれば……それも悪くないね。","ENG":"If I can take away nightmares... That doesn’t sound too bad.","TWN":"只要可以把惡夢帶走……那好像也不錯。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"무슨 말도 안 되는 소리야!","JPN":"何言ってるんだよ！","ENG":"Don't be ridiculous!","TWN":"你在說什麼傻話！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네가 왜 이렇게까지 하려는지는 몰라도 나쁜 일에 이용당하면서까지 할 일은 아니라고 봐!","JPN":"なんでアンタがここまでしようとするのかはわかんないけど、悪だくみに利用されてまでやることじゃないと思う！","ENG":"I'm not sure why you want to do it, but getting involved with criminals is not worth it!","TWN":"我不知道為什麼你要做到這種程度，但至少不能被利用來做壞事吧！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다가 그렇다면 그런 거겠지? 그럼 그건 안 할래.","JPN":"グリンダが言うならそうなんだろうね。じゃあ、それはやらない。","ENG":"Glinda, if you say so, it must be true, right? Then I won’t do it.","TWN":"格琳達說的一定有你的道理，那我不會那麼做的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 멍청아! 자꾸 답답하게 굴래?!","JPN":"このバカ！　いつも焦れったいんだから！","ENG":"You moron! Will you please stop being so thick?!","TWN":"你這傻瓜！還要惹我生氣嗎？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하아……. 아무래도 방법은 하나뿐이야.","JPN":"はあ……どうやら残った方法は一つだけみたいだね。","ENG":"Ugh... I guess there’s only one way out of this.","TWN":"哀……方法只剩一個。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"얼른 도망가. 뒤는 내가 어떻게든 수습해볼 테니까.","JPN":"早く逃げな。あとは私がなんとかしてみるから。","ENG":"Run. I’ll cover for you.","TWN":"你快逃吧，其他的事我會想辦法處理的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"못 미더운 거 알겠는데 나도 큰 결심하고 말하는 거거든?","JPN":"頼りないってのはわかってるけど、私も結構な覚悟して言ってるんだ。","ENG":"I understand your suspicion, but this is a big decision for me, you know?","TWN":"我知道你不敢置信，我也是下定很大的決心好嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님... 아니 헤이븐 그 사람. 정말 널 만신창이로 만들어 버릴 수 있는 사람이야.","JPN":"ヘイブン兄貴……いや、ヘイブンって人。本当にアンタをボロボロにできる人なんだ。","ENG":"Boss... I mean, Haven... He's the type of person who can seriously hurt you.","TWN":"天堂大哥…不，是天堂那個人，他絕對有能力把你弄到生不如死的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 랜드도 잘 도망다녔다며. 혼자라면 이쯤은 그냥 탈출할 수 있는 거 아냐?","JPN":"ヘイブンランドでもうまく逃げまわったらしいじゃん。一人ならこのくらい余裕で脱出できるんじゃない？","ENG":"You managed to escape from Havenland, right? Doesn’t that mean you can escape this place too?","TWN":"你不是說天堂樂園你很熟嗎？那你自己應該也逃得出去吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"난…… 그래도 여기 사람이었는데. 설마 죽이진 않겠지.","JPN":"私は……それでもここの人間だったんだから。まさか殺さないでしょ。","ENG":"I mean... They won’t kill me, right? I used to belong here.","TWN":"我……至少是這裡的人，他們應該不至於殺我。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 아무튼 그러니까 빨리 도망가라고!","JPN":"と、とにかく、だから早く逃げなって！","ENG":"A-anyway, just go already!","TWN":"總…總之你快逃啦！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"혼자는 안 가.","JPN":"一人じゃ行かない。","ENG":"I’m not leaving alone.","TWN":"我不會自己逃的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"또 답답하게 굴 작정이라면 나도……!","JPN":"また焦れったくする気なら私も……！","ENG":"Ugh, will you stop being so stubborn? Do you thi─","TWN":"你又想惹我生氣嗎？那我……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네가 그랬잖아.","JPN":"グリンダが言ったじゃない。","ENG":"But you said.","TWN":"是你自己說的，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"계속 같이 지내자고.","JPN":"ずっと一緒にいようって。","ENG":"That we’d keep working together.","TWN":"要繼續一起生活。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 아무튼 루루. 우리 같은 인연이 또 어디 있겠어?","JPN":"と、とにかくルル。私たちみたいな縁はどこにもないんだ。","ENG":"A-anyway, Lulu. We make a great team, no?","TWN":"那個，露露，我們的緣分也真很奇妙，你說是不是？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이런 게 바로 운명이지. 그, 정령님이라는 분이 나한테 널 인도해 주셨을 수도!","JPN":"これこそ運命だよ。その、精霊様って方が私にアンタを導いてくれたのかも！","ENG":"If that’s not fate, I don’t know what is! Maybe it was that spirit that guided me to you?","TWN":"這就是命運的相遇吧？可能是那個精靈大人藉由我引導你的！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이런 식으로 계속 같이 지내자. 넌 악몽을 없애고, 나는 돈을 벌고. 어때? 이 정도면 좋은 파트너 아냐?","JPN":"こんな風にずっと一緒にいよう。アンタは悪夢を消して、私をお金を稼いで。どう？　これならいいパートナーじゃない？","ENG":"Let's keep working together like this. I make money while you get rid of nightmares. So? Doesn’t that sound like the perfect partner?","TWN":"我們就繼續一起生活下去吧！你負責消除惡夢，我負責賺錢，怎麼樣？這樣應該算是好夥伴吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그거야 네가 떠날까 봐 걱정돼서 한 소리지!","JPN":"そりゃあ、アンタがどっか行っちゃうか心配で言ったんだよ！","ENG":"That was because I was worried you might leave!","TWN":"我會那麼說是因為怕你離開！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너 없으면 나 혼자 할 수 있는 게 없으니까!","JPN":"アンタがいないと、私一人でできることなんてないから！","ENG":"And without you, there’s nothing I can do!","TWN":"沒有你的話，我一個人就是一事無成！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"몇백 살 먹은 노인네처럼 굴 땐 언제고, 순진하게 그걸 믿냐?!","JPN":"いつぞやは何百歳のおばあちゃんみたいに行動しておいて、素直にそれを信じる！？","ENG":"You used to act like some wise, old elder, but now you act naive?","TWN":"你不是跟老人家一樣固執嗎？現在又那麼聽話是怎樣？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네가 왜 할 줄 아는 게 없어? 잠잘 곳도 잘 만들고, 공짜로 밥도 먹을 수 있고, 보잘 것 없는 능력으로 돈도 벌 수 있는데?","JPN":"できることがないって？　寝床も作れるし、ただでご飯も食べられるし、つまらない能力でお金も稼げるのに？","ENG":"Why do you believe you can't do anything? You know how to make a good bed, find places that give out free food, and make money off my useless ability.","TWN":"你怎麼會一事無成？你會做床，還會利用渺小的能力賺錢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그건…… 그건 정말 누구나 할 수 있는 하찮은 일이잖아!","JPN":"それは……それは本当に誰でもできるつまんないことじゃん！","ENG":"But those... are things that anyone can do!","TWN":"那些事……根本大家都做得到吧？！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래도 나에게 그런 말을 해준 사람은 글린다가 처음인 걸.","JPN":"でも私にそんなこと言ってくれた人はグリンダが初めてだもん。","ENG":"Still, you're the first person to say those things to me, Glinda.","TWN":"但你是第一個那麼對我說的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런 건 다 소용없어. 누구나 입 발린 말은 할 수 있으니까.","JPN":"そんなの全部役に立たないんだよ。誰でもお世辞は言えるから。","ENG":"That doesn’t help. Anyone can say stuff like that.","TWN":"那有什麼用？出一張嘴誰不會。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"난 널 두고 도망도 쳤다고. 몰랐지? 그래서 네가 잡힌 거야.","JPN":"私はアンタを置いて逃げたんだよ。知らなかったでしょ？　だからアンタが捕まっちゃったの。","ENG":"You don’t know that I ditched you and tried to save myself, do you? That’s why you got caught.","TWN":"我扔下你自己逃跑！你不知道吧？所以你才會被抓！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그것도 괜찮아. 내가 정신을 잃은 탓인 걸.","JPN":"それも大丈夫だよ。私が気を失ったせいだし。","ENG":"It’s all right. It’s my fault I lost consciousness in the first place.","TWN":"我不介意，都怪我自己暈過去。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"말 같지도 않은 소리는 그만하고 얼른 가. 내가 좋은 말로 뒤 봐준다고 할 때.","JPN":"くだらない話してないで、早く行きな。後は任せろって言ってるうちにね。","ENG":"Stop babbling and go already before I regret what I’m about to do.","TWN":"不要再說這些莫名其妙的話，趕快逃，趁我還沒改變心意之前！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다. 잠시만.","JPN":"グリンダ。ちょっと待って。","ENG":"Glinda. Hold on.","TWN":"格琳達，先等一下。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너 진짜......!","JPN":"アンタね……！","ENG":"Oh, come on...!","TWN":"你真的是……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"알았어. 정말 잠깐이면 돼.","JPN":"わかった。本当に少しでいいよ。","ENG":"Okay. It’ll only take a second.","TWN":"先等一下就好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네게 꼭 해 줄 말이 있어.","JPN":"伝えなきゃいけないことがあるの。","ENG":"I have something I need to tell you.","TWN":"我有話一定要跟你說。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};